# ============================================================
#  Glassmorphism UI apply karne wali script
#  Cyclone-Alert folder ke ANDAR se chalao:
#     powershell -ExecutionPolicy Bypass -File apply-glass-ui.ps1
#  Ya line-by-line copy-paste karo (neeche 3 steps).
# ============================================================

Write-Host "1/3  fonts folder bana rahe hain..." -ForegroundColor Cyan
New-Item -ItemType Directory -Force -Path "public\fonts" | Out-Null

Write-Host "2/3  index.css likh rahe hain (glassmorphism)..." -ForegroundColor Cyan
$b64 = ""
[IO.File]::WriteAllBytes("src\index.css", [Convert]::FromBase64String($b64))

Write-Host "3/3  ho gaya! Ab ClashGrotesk-Light.otf aur ClashGrotesk-Bold.otf ko" -ForegroundColor Green
Write-Host "     public\fonts\ folder me copy karo (manually / drag-drop)." -ForegroundColor Green
Write-Host ""
Write-Host "Phir browser me Ctrl+Shift+R maaro." -ForegroundColor Yellow

Write-Host "4/4  AlertBanner.jsx update kar rahe hain (dynamic glow)..." -ForegroundColor Cyan
$bBanner = ""
[IO.File]::WriteAllBytes("src\components\AlertBanner.jsx", [Convert]::FromBase64String($bBanner))
Write-Host "     AlertBanner done." -ForegroundColor Green
